with.prompt:
Build a deterministic, video-ready SvelteKit app in /tmp/{{trigger.repo}}.

Original request:
{{trigger.prompt}}

Product framing:
- App name: {{trigger.app_name}}
- Headline: {{trigger.headline}}
- Description: {{trigger.description}}
- UI brief: {{trigger.ui_brief}}
- Implementation brief: {{trigger.implementation_brief}}

Browser demo contract:
{{trigger.capture_steps_json}}

Use ONE Bash tool call only. Copy this script exactly. Do not add extra tool calls.

set -euo pipefail
REPO='{{trigger.repo}}'
APP_NAME='{{trigger.app_name}}'
HEADLINE='{{trigger.headline}}'
DESCRIPTION='{{trigger.description}}'
PROMPT_TEXT='{{trigger.prompt}}'
IMPLEMENTATION_BRIEF='{{trigger.implementation_brief}}'
CAPTURE_STEPS='{{trigger.capture_steps_json}}'

cd /tmp/${REPO}
rm -rf src static node_modules .svelte-kit build package-lock.json package.json svelte.config.js vite.config.js jsconfig.json tsconfig.json README.md
mkdir -p src/routes static

cat > package.json <<PKG
{
  "name": "${REPO}",
  "private": true,
  "version": "0.0.1",
  "type": "module",
  "scripts": {
    "dev": "vite dev --host 0.0.0.0 --port 3000",
    "build": "vite build",
    "preview": "vite preview --host 0.0.0.0 --port 3000"
  },
  "devDependencies": {
    "@sveltejs/adapter-auto": "^6.1.0",
    "@sveltejs/kit": "^2.31.1",
    "@sveltejs/vite-plugin-svelte": "^6.1.3",
    "leaflet": "^1.9.4",
    "svelte": "^5.38.6",
    "vite": "^7.1.3"
  }
}
PKG

cat > svelte.config.js <<'EOF'
import adapter from '@sveltejs/adapter-auto';

export default {
  kit: {
    adapter: adapter()
  }
};
EOF

cat > vite.config.js <<'EOF'
import { sveltekit } from '@sveltejs/kit/vite';
import { defineConfig } from 'vite';

export default defineConfig({
  plugins: [sveltekit()]
});
EOF

cat > jsconfig.json <<'EOF'
{
  "compilerOptions": {
    "module": "esnext",
    "moduleResolution": "bundler",
    "target": "es2022",
    "allowJs": true,
    "checkJs": false
  }
}
EOF

cat > src/app.html <<'EOF'
<!doctype html>
<html lang="en">
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    %sveltekit.head%
  </head>
  <body data-sveltekit-preload-data="hover">
    <div style="display: contents">%sveltekit.body%</div>
  </body>
</html>
EOF

APP_NAME="$APP_NAME" HEADLINE="$HEADLINE" DESCRIPTION="$DESCRIPTION" PROMPT_TEXT="$PROMPT_TEXT" IMPLEMENTATION_BRIEF="$IMPLEMENTATION_BRIEF" CAPTURE_STEPS="$CAPTURE_STEPS" node <<'EOF'
const fs = require('node:fs');
const path = require('node:path');
const appName = process.env.APP_NAME || 'Signal Room';
const headline = process.env.HEADLINE || appName;
const description = process.env.DESCRIPTION || '';
const prompt = `${process.env.PROMPT_TEXT || ''} ${process.env.IMPLEMENTATION_BRIEF || ''}`;
const wantsMap = /map|vessel|route|cargo|overlay|strait of hormuz|maritime/i.test(prompt);
const steps = JSON.parse(process.env.CAPTURE_STEPS || '[]');
const selectors = [...new Set(steps.flatMap((step) => [step.selector, step.waitForSelector]).filter((value) => typeof value === 'string' && value.includes('data-demo')))];
const hasSelector = (name) => selectors.some((selector) => selector.includes(name));
const mapTemplate = `
<script>
  import { onMount } from 'svelte';
  import 'leaflet/dist/leaflet.css';

  const baseVessels = [
    { id: 'atlas-runner', name: 'Atlas Runner', lat: 26.78, lng: 56.24, cargo: 'LNG', status: 'Inbound', risk: 'Low', throughput: 84 },
    { id: 'horizon-spirit', name: 'Horizon Spirit', lat: 26.52, lng: 56.41, cargo: 'Crude', status: 'Holding', risk: 'Medium', throughput: 72 },
    { id: 'strait-vector', name: 'Strait Vector', lat: 26.36, lng: 56.12, cargo: 'Refined', status: 'Escorted', risk: 'High', throughput: 65 }
  ];

  let mapHost;
  let map;
  let L;
  let overlayActive = false;
  let filteredFleet = false;
  let selectedVesselId = baseVessels[0].id;
  let throughputTotal = 221;
  let incidentPulse = 3;
  let liveClock = '';
  let markers = [];
  let routeLayer;
  let overlayLayer;

  const alerts = [
    'Escort window narrows in 14 minutes',
    'Thermal spike detected near outbound lane',
    'Pilot transfer queue updated for northern channel'
  ];

  function getVisibleVessels() {
    return filteredFleet ? baseVessels.filter((v) => v.risk !== 'High') : baseVessels;
  }

  function getSelectedVessel() {
    return getVisibleVessels().find((v) => v.id === selectedVesselId) || getVisibleVessels()[0] || baseVessels[0];
  }

  function selectVessel(id) {
    selectedVesselId = id;
    redrawMap();
  }

  function toggleOverlay() {
    overlayActive = !overlayActive;
    redrawMap();
  }

  function toggleFleetFilter() {
    filteredFleet = !filteredFleet;
    if (!getVisibleVessels().some((v) => v.id === selectedVesselId)) {
      selectedVesselId = getVisibleVessels()[0]?.id || baseVessels[0].id;
    }
    redrawMap();
  }

  function redrawMap() {
    if (!map || !L) return;
    markers.forEach((marker) => marker.remove());
    markers = [];
    if (routeLayer) routeLayer.remove();
    if (overlayLayer) overlayLayer.remove();

    const vessels = getVisibleVessels();
    const selected = getSelectedVessel();
    const route = vessels.map((v) => [v.lat, v.lng]);

    routeLayer = L.polyline(route, {
      color: '#7dd3fc',
      weight: 3,
      opacity: 0.8,
      dashArray: '10 8'
    }).addTo(map);

    if (overlayActive) {
      overlayLayer = L.polygon([
        [26.92, 55.85],
        [26.85, 56.62],
        [26.05, 56.45],
        [26.12, 55.78]
      ], {
        color: '#fb7185',
        fillColor: '#fb7185',
        fillOpacity: 0.12,
        weight: 1.5
      }).addTo(map);
    }

    vessels.forEach((vessel) => {
      const marker = L.circleMarker([vessel.lat, vessel.lng], {
        radius: vessel.id === selected.id ? 10 : 7,
        color: vessel.id === selected.id ? '#f8fafc' : '#0f172a',
        weight: vessel.id === selected.id ? 3 : 2,
        fillColor: vessel.risk === 'High' ? '#fb7185' : vessel.risk === 'Medium' ? '#f59e0b' : '#22c55e',
        fillOpacity: 0.95
      }).addTo(map);
      marker.on('click', () => selectVessel(vessel.id));
      marker.bindTooltip(vessel.name, { direction: 'top', offset: [0, -10] });
      markers.push(marker);
    });

    map.fitBounds(routeLayer.getBounds(), { padding: [24, 24] });
  }

  onMount(async () => {
    const leafletModule = await import('leaflet');
    L = leafletModule.default ?? leafletModule;
    map = L.map(mapHost, { zoomControl: false, attributionControl: false }).setView([26.47, 56.22], 8);
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
      maxZoom: 12,
      minZoom: 6
    }).addTo(map);
    redrawMap();

    const interval = setInterval(() => {
      liveClock = new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
      throughputTotal = 210 + Math.round(Math.random() * 25);
      incidentPulse = 2 + Math.round(Math.random() * 4);
      baseVessels.forEach((vessel, index) => {
        vessel.lat += (Math.random() - 0.5) * 0.015;
        vessel.lng += (Math.random() - 0.5) * 0.015;
        vessel.throughput = Math.max(48, Math.min(96, vessel.throughput + (index - 1) * 2 + Math.round((Math.random() - 0.5) * 6)));
      });
      redrawMap();
    }, 2500);

    liveClock = new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit' });

    return () => {
      clearInterval(interval);
      map?.remove();
    };
  });

</script>

<svelte:head>
  <title>${headline}</title>
  <meta name="description" content="${description}" />
</svelte:head>

<div class="shell">
  <section class="hero">
    <div>
      <p class="eyebrow">${appName}</p>
      <h1>${headline}</h1>
      <p class="lede">${description}</p>
    </div>
    <div class="hero-meta">
      <div>
        <span>Live Clock</span>
        <strong>{liveClock}</strong>
      </div>
      <div>
        <span>Fleet Throughput</span>
        <strong>{throughputTotal} kt/day</strong>
      </div>
      <div>
        <span>Incident Pulse</span>
        <strong>{incidentPulse} active</strong>
      </div>
    </div>
  </section>

  <section class="layout">
    <div class="map-card">
      <div class="map-toolbar">
        <div>
          <p class="section-label">Strait Corridor</p>
          <h2>Realtime vessel picture</h2>
        </div>
        <div class="map-actions">
          <button data-demo="overlay-toggle" class:active={overlayActive} on:click={toggleOverlay}>${hasSelector('overlay-toggle') ? 'Toggle Overlay' : 'Overlay'}</button>
          <button data-demo="fleet-filter" class:active={filteredFleet} on:click={toggleFleetFilter}>${hasSelector('fleet-filter') ? 'Filter Fleet' : 'Fleet Filter'}</button>
        </div>
      </div>
      {#if overlayActive}<p class="banner">Overlay active</p>{/if}
      {#if filteredFleet}<p class="banner alt">Filtered fleet</p>{/if}
      <div class="map-stage" data-demo="map-stage" bind:this={mapHost}></div>
      <div class="vessel-strip">
        {#each getVisibleVessels() as vessel, index}
          <button data-demo={index === 0 ? 'vessel-marker' : undefined} class:selected={vessel.id === getSelectedVessel().id} on:click={() => selectVessel(vessel.id)}>
            <span>{vessel.name}</span>
            <strong>{vessel.cargo}</strong>
          </button>
        {/each}
      </div>
    </div>

    <aside class="side-rail">
      <section class="detail-card" data-demo="vessel-detail">
        <p class="section-label">Selected Vessel</p>
        <h3>{getSelectedVessel().name}</h3>
        <dl>
          <div><dt>Status</dt><dd>{getSelectedVessel().status}</dd></div>
          <div><dt>Cargo</dt><dd>{getSelectedVessel().cargo}</dd></div>
          <div><dt>Risk</dt><dd>{getSelectedVessel().risk}</dd></div>
          <div><dt>Throughput</dt><dd>{getSelectedVessel().throughput} kt</dd></div>
        </dl>
      </section>

      <section class="analytics-card" data-demo="analytics-panel">
        <p class="section-label">Live Analytics</p>
        <div class="analytics-grid">
          <article><span>Transit cadence</span><strong>{throughputTotal}</strong></article>
          <article><span>Channel risk</span><strong>{incidentPulse}</strong></article>
          <article><span>Visible fleet</span><strong>{getVisibleVessels().length}</strong></article>
          <article><span>Overlay state</span><strong>{overlayActive ? 'Adaptive' : 'Baseline'}</strong></article>
        </div>
      </section>

      <section class="feed-card" data-demo="incident-feed">
        <p class="section-label">Incident Feed</p>
        <ul>
          {#each alerts as alert, index}
            <li><span>{index + 1}</span><p>{alert}</p></li>
          {/each}
        </ul>
      </section>
    </aside>
  </section>
</div>

<style>
  :global(body) {
    margin: 0;
    font-family: Inter, ui-sans-serif, system-ui, sans-serif;
    background: radial-gradient(circle at top, #15314d, #020617 58%);
    color: #e2e8f0;
  }
  .shell { padding: 32px; display: grid; gap: 24px; min-height: 100vh; box-sizing: border-box; }
  .hero { display: flex; justify-content: space-between; gap: 24px; align-items: end; }
  .eyebrow, .section-label { text-transform: uppercase; letter-spacing: 0.18em; font-size: 0.72rem; color: #7dd3fc; margin: 0 0 12px; }
  h1 { font-size: clamp(2.4rem, 5vw, 4.4rem); line-height: 0.95; margin: 0; max-width: 11ch; }
  .lede { color: #cbd5e1; max-width: 58ch; }
  .hero-meta { display: grid; grid-template-columns: repeat(3, minmax(120px, 1fr)); gap: 12px; }
  .hero-meta div, .map-card, .detail-card, .analytics-card, .feed-card { background: rgba(15, 23, 42, 0.72); border: 1px solid rgba(125, 211, 252, 0.16); border-radius: 20px; box-shadow: 0 24px 60px rgba(2, 8, 23, 0.36); }
  .hero-meta div { padding: 14px 16px; }
  .hero-meta span { display: block; color: #94a3b8; font-size: 0.82rem; }
  .hero-meta strong { font-size: 1.2rem; }
  .layout { display: grid; grid-template-columns: minmax(0, 1.8fr) minmax(300px, 0.9fr); gap: 20px; }
  .map-card { padding: 18px; display: grid; gap: 16px; }
  .map-toolbar { display: flex; justify-content: space-between; gap: 16px; align-items: center; }
  .map-toolbar h2 { margin: 0; font-size: 1.35rem; }
  .map-actions { display: flex; gap: 10px; flex-wrap: wrap; }
  button { border: 0; border-radius: 999px; padding: 10px 14px; cursor: pointer; background: rgba(15, 23, 42, 0.85); color: #e2e8f0; border: 1px solid rgba(148, 163, 184, 0.2); }
  button.active, .vessel-strip button.selected { background: linear-gradient(135deg, #38bdf8, #0f172a); color: white; border-color: rgba(125, 211, 252, 0.55); }
  .banner { margin: 0; color: #67e8f9; font-weight: 700; }
  .banner.alt { color: #fbbf24; }
  .map-stage { height: 540px; border-radius: 18px; overflow: hidden; border: 1px solid rgba(125, 211, 252, 0.18); }
  .vessel-strip { display: grid; grid-template-columns: repeat(auto-fit, minmax(160px, 1fr)); gap: 10px; }
  .vessel-strip button { text-align: left; display: grid; gap: 6px; border-radius: 16px; }
  .side-rail { display: grid; gap: 16px; }
  .detail-card, .analytics-card, .feed-card { padding: 18px; }
  .detail-card h3 { margin: 0 0 12px; font-size: 1.5rem; }
  dl { display: grid; gap: 10px; margin: 0; }
  dl div { display: flex; justify-content: space-between; gap: 12px; color: #cbd5e1; }
  dt { color: #94a3b8; }
  .analytics-grid { display: grid; grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 12px; }
  .analytics-grid article { padding: 14px; border-radius: 16px; background: rgba(30, 41, 59, 0.65); }
  .analytics-grid span { display: block; color: #94a3b8; font-size: 0.82rem; }
  .analytics-grid strong { font-size: 1.35rem; }
  .feed-card ul { list-style: none; padding: 0; margin: 0; display: grid; gap: 12px; }
  .feed-card li { display: grid; grid-template-columns: 28px 1fr; gap: 12px; align-items: start; }
  .feed-card span { display: inline-grid; place-items: center; width: 28px; height: 28px; border-radius: 999px; background: rgba(248, 113, 113, 0.15); color: #fda4af; font-weight: 700; }
  .feed-card p { margin: 0; color: #cbd5e1; }
  @media (max-width: 980px) { .hero, .layout { grid-template-columns: 1fr; display: grid; } .hero-meta { grid-template-columns: repeat(3, minmax(0,1fr)); } .map-stage { height: 420px; } }
</style>
`;
const genericTemplate = `
<script>
  let pulse = 82;
  let mode = 'Live';
  const interval = setInterval(() => { pulse = 76 + Math.round(Math.random() * 18); mode = mode === 'Live' ? 'Adaptive' : 'Live'; }, 2200);
</script>

<svelte:head>
  <title>${headline}</title>
  <meta name="description" content="${description}" />
</svelte:head>

<div class="fallback-shell">
  <p>${appName}</p>
  <h1>${headline}</h1>
  <p>${description}</p>
  <section data-demo="analytics-panel">
    <article><span>Signal pulse</span><strong>{pulse}</strong></article>
    <article><span>Mode</span><strong>{mode}</strong></article>
  </section>
</div>

<style>
  :global(body){margin:0;font-family:Inter,ui-sans-serif,system-ui,sans-serif;background:#020617;color:#e2e8f0}
  .fallback-shell{min-height:100vh;padding:40px;display:grid;gap:18px;background:radial-gradient(circle at top,#1d4ed8,#020617 55%)}
  h1{margin:0;font-size:clamp(2.5rem,5vw,4rem)}
  section{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:12px}
  article{padding:18px;border-radius:18px;background:rgba(15,23,42,.72)}
  span{display:block;color:#93c5fd}
  strong{font-size:1.5rem}
</style>
`;
fs.writeFileSync(path.join(process.cwd(), 'src/routes/+page.svelte'), wantsMap ? mapTemplate : genericTemplate);
EOF

